#include<iostream>
using namespace std;

int n, t = 0;
int r[14];
bool a[15][15];
bool col[15];
bool d1[30];
bool d2[30];

void qq(int op) {
	if (op == n + 1) {
		t++;
		return;
	}
	for (int i = 1; i <= n; i++) {
		if (!a[op][i] || col[i] || d1[op + i] || d2[op - i + n])
			continue;
		col[i] = 1;
		d1[op + i] = 1;
		d2[op - i + n] = 1;
		qq(op + 1);
		col[i] = 0;
		d1[op + i] = 0; 

		d2[op - i + n] = 0;
	}
}

int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			char c;
			cin >> c;
			a[i][j] = (c == '*');
		}
	}
	qq(1);
	cout << t << endl;
	return 0;
}
